def _dremio_virtual_dataset_to_nested(
    dremio_virtual_dataset: DremioVirtualDataset,
) -> DremioVirtualDatasetNested:
    """Convert flat DremioVirtualDataset to nested format."""
    attrs = DremioVirtualDatasetAttributes()
    _populate_dremio_virtual_dataset_attrs(attrs, dremio_virtual_dataset)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dremio_virtual_dataset,
        _DREMIO_VIRTUAL_DATASET_REL_FIELDS,
        DremioVirtualDatasetRelationshipAttributes,
    )
    return DremioVirtualDatasetNested(
        guid=dremio_virtual_dataset.guid,
        type_name=dremio_virtual_dataset.type_name,
        status=dremio_virtual_dataset.status,
        version=dremio_virtual_dataset.version,
        create_time=dremio_virtual_dataset.create_time,
        update_time=dremio_virtual_dataset.update_time,
        created_by=dremio_virtual_dataset.created_by,
        updated_by=dremio_virtual_dataset.updated_by,
        classifications=dremio_virtual_dataset.classifications,
        classification_names=dremio_virtual_dataset.classification_names,
        meanings=dremio_virtual_dataset.meanings,
        labels=dremio_virtual_dataset.labels,
        business_attributes=dremio_virtual_dataset.business_attributes,
        custom_attributes=dremio_virtual_dataset.custom_attributes,
        pending_tasks=dremio_virtual_dataset.pending_tasks,
        proxy=dremio_virtual_dataset.proxy,
        is_incomplete=dremio_virtual_dataset.is_incomplete,
        provenance_type=dremio_virtual_dataset.provenance_type,
        home_id=dremio_virtual_dataset.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dremio_virtual_dataset_from_nested(
    nested: DremioVirtualDatasetNested,
) -> DremioVirtualDataset:
    """Convert nested format to flat DremioVirtualDataset."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DremioVirtualDatasetAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DREMIO_VIRTUAL_DATASET_REL_FIELDS,
        DremioVirtualDatasetRelationshipAttributes,
    )
    return DremioVirtualDataset(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dremio_virtual_dataset_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dremio_virtual_dataset_to_nested_bytes(
    dremio_virtual_dataset: DremioVirtualDataset, serde: Serde
) -> bytes:
    """Convert flat DremioVirtualDataset to nested JSON bytes."""
    return serde.encode(_dremio_virtual_dataset_to_nested(dremio_virtual_dataset))


def _dremio_virtual_dataset_from_nested_bytes(
    data: bytes, serde: Serde
) -> DremioVirtualDataset:
    """Convert nested JSON bytes to flat DremioVirtualDataset."""
    nested = serde.decode(data, DremioVirtualDatasetNested)
    return _dremio_virtual_dataset_from_nested(nested)


